<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1.0"/>
<title>ACM-W India</title>
<link rel="icon" type="image/png" href="data:image/png;base64,"/>

<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400;1,600&family=Plus+Jakarta+Sans:wght@300;400;500;600&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
:root{--navy:#0a1628;--deep:#0d2148;--royal:#1a4fad;--bright:#2563eb;--sky:#3b82f6;--light:#93c5fd;--pale:#dbeafe;--white:#f0f6ff;--muted:#64748b;--border:#bfdbfe;--card:#fff}
html{scroll-behavior:smooth}
body{font-family:'Plus Jakarta Sans',sans-serif;background:var(--white);color:var(--navy);overflow-x:hidden}
nav{position:fixed;top:0;left:0;right:0;z-index:200;height:68px;display:flex;align-items:center;justify-content:space-between;padding:0 5vw;background:rgba(10,22,40,.97);backdrop-filter:blur(16px);border-bottom:1px solid rgba(255,255,255,.07);transition:box-shadow .3s}
nav.scrolled{box-shadow:0 4px 32px rgba(10,22,40,.4)}
.nav-brand{display:flex;align-items:center;gap:12px;cursor:pointer}
.nav-logo{width:38px;height:38px;background:linear-gradient(135deg,var(--bright),var(--sky));display:flex;align-items:center;justify-content:center;font-family:'Playfair Display',serif;font-size:1rem;font-weight:700;color:#fff;border-radius:6px}
.nb-main{font-size:.88rem;font-weight:600;color:#fff;letter-spacing:.04em;display:block}
.nb-sub{font-size:.63rem;letter-spacing:.14em;text-transform:uppercase;color:var(--light);display:block}
.nav-tabs{display:flex;gap:2px}
.nav-tab{position:relative;padding:8px 22px;border:none;background:transparent;font-family:'Plus Jakarta Sans',sans-serif;font-size:.78rem;font-weight:500;letter-spacing:.08em;text-transform:uppercase;color:rgba(255,255,255,.5);cursor:pointer;transition:color .2s;text-decoration:none;display:inline-flex;align-items:center}
.nav-tab::after{content:'';position:absolute;bottom:0;left:22px;right:22px;height:2px;background:var(--sky);transform:scaleX(0);transform-origin:center;transition:transform .3s}
.nav-tab.active,.nav-tab:hover{color:#fff}
.nav-tab.active::after{transform:scaleX(1)}
.page{display:block;padding-top:0;animation:none}
@keyframes fadeUp{from{opacity:0;transform:translateY(18px)}to{opacity:1;transform:translateY(0)}}
.hero{position:relative;min-height:calc(100vh - 68px);display:flex;align-items:center;justify-content:center;overflow:hidden;padding:60px 0;padding-top:68px}
.hero-bg{position:absolute;inset:0;background:linear-gradient(150deg,#050d1a 0%,#0a1f4e 55%,#0d2a6b 100%)}
.hero-grid{position:absolute;inset:0;opacity:.06;background-image:linear-gradient(rgba(147,197,253,.8) 1px,transparent 1px),linear-gradient(90deg,rgba(147,197,253,.8) 1px,transparent 1px);background-size:48px 48px}
.orb{position:absolute;border-radius:50%;filter:blur(80px);pointer-events:none}
.orb1{width:700px;height:700px;top:-200px;right:-150px;background:radial-gradient(circle,rgba(37,99,235,.35) 0%,transparent 70%);animation:drift 8s ease-in-out infinite}
.orb2{width:500px;height:500px;bottom:-150px;left:-80px;background:radial-gradient(circle,rgba(124,58,237,.25) 0%,transparent 70%);animation:drift 10s ease-in-out infinite reverse}
.orb3{width:300px;height:300px;top:40%;left:38%;background:radial-gradient(circle,rgba(59,130,246,.2) 0%,transparent 70%);animation:drift 7s ease-in-out infinite 2s}
@keyframes drift{0%,100%{transform:translate(0,0) scale(1)}50%{transform:translate(30px,-30px) scale(1.05)}}
.hero-content{position:relative;z-index:2;padding:0 10vw;width:100%;text-align:center}
.hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(37,99,235,.2);border:1px solid rgba(59,130,246,.3);padding:6px 16px;border-radius:100px;margin-bottom:28px}
.bdot{width:7px;height:7px;border-radius:50%;background:var(--sky);animation:blink 2s infinite}
@keyframes blink{0%,100%{opacity:1}50%{opacity:.3}}
.hero-badge span{font-size:.72rem;letter-spacing:.15em;text-transform:uppercase;color:var(--light);font-weight:500}
.hero-title{font-family:'Playfair Display',serif;font-size:clamp(2.6rem,6vw,5rem);font-weight:700;line-height:1.1;color:#fff;margin-bottom:10px}
.grad{font-style:italic;color:transparent;background:linear-gradient(90deg,var(--sky),var(--light));-webkit-background-clip:text;background-clip:text}
.hero-sub{font-size:.95rem;line-height:1.85;font-weight:300;color:rgba(200,220,255,.65);max-width:680px;margin:20px 0 44px}
.hbtns{display:flex;gap:14px;flex-wrap:wrap}
.btnp{display:inline-flex;align-items:center;gap:10px;padding:14px 32px;border:none;cursor:pointer;background:linear-gradient(135deg,var(--bright),var(--royal));color:#fff;font-family:'Plus Jakarta Sans',sans-serif;font-size:.82rem;font-weight:600;letter-spacing:.06em;text-transform:uppercase;border-radius:4px;box-shadow:0 4px 24px rgba(37,99,235,.45);transition:transform .2s,box-shadow .2s}
.btnp:hover{transform:translateY(-2px);box-shadow:0 8px 32px rgba(37,99,235,.55)}
.btns{display:inline-flex;align-items:center;gap:10px;padding:14px 32px;cursor:pointer;background:transparent;border:1px solid rgba(147,197,253,.35);color:var(--light);font-family:'Plus Jakarta Sans',sans-serif;font-size:.82rem;font-weight:500;letter-spacing:.06em;text-transform:uppercase;border-radius:4px;transition:background .2s}
.btns:hover{background:rgba(147,197,253,.08)}
.stats-band{display:flex;justify-content:center;flex-wrap:wrap;background:rgba(13,33,72,.95);border-bottom:1px solid rgba(147,197,253,.12)}
.stats-band .si{padding:28px 48px;text-align:center;border-right:1px solid rgba(147,197,253,.12)}
.stats-band .si:last-child{border-right:none}
.hstats{position:absolute;bottom:0;right:0;display:flex;background:rgba(13,33,72,.7);backdrop-filter:blur(16px);border-top:1px solid rgba(147,197,253,.12);border-left:1px solid rgba(147,197,253,.12)}
.si{padding:28px 36px;text-align:center;border-right:1px solid rgba(147,197,253,.12)}
.si:last-child{border-right:none}
.sn{font-family:'Playfair Display',serif;font-size:2.1rem;font-weight:700;line-height:1;background:linear-gradient(135deg,var(--sky),var(--light));-webkit-background-clip:text;background-clip:text;color:transparent}
.sl{font-size:.66rem;letter-spacing:.14em;text-transform:uppercase;color:rgba(147,197,253,.5);margin-top:6px}
.sec{padding:88px 8vw}.sec.wh{background:#fff}
.stag{display:inline-flex;align-items:center;gap:10px;font-size:.72rem;letter-spacing:.18em;text-transform:uppercase;color:var(--bright);font-weight:600;margin-bottom:14px}
.stag::before{content:'';width:20px;height:2px;background:var(--bright)}
.stag.c{display:flex;justify-content:center}
.sh{font-family:'Playfair Display',serif;font-size:clamp(1.8rem,3.5vw,2.8rem);font-weight:600;line-height:1.2;max-width:560px;margin-bottom:48px}
.sh em{font-style:italic;color:var(--bright)}.sh.c{text-align:center;margin-left:auto;margin-right:auto}
.pillars{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}
.pillar{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:36px 28px;position:relative;overflow:hidden;transition:transform .3s,box-shadow .3s}
.pillar::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--bright),var(--sky))}
.pillar:hover{transform:translateY(-6px);box-shadow:0 16px 48px rgba(37,99,235,.14)}
.pico{width:52px;height:52px;border-radius:10px;margin-bottom:22px;background:linear-gradient(135deg,var(--pale),var(--border));display:flex;align-items:center;justify-content:center;color:var(--bright)}
.pti{font-family:'Playfair Display',serif;font-size:1.2rem;font-weight:600;margin-bottom:10px}
.ptx{font-size:.86rem;line-height:1.8;color:var(--muted)}
.qband{background:linear-gradient(135deg,var(--deep),#0d2a6b);padding:80px 8vw;text-align:center;position:relative;overflow:hidden}
.qband::before{content:'\201C';font-family:'Playfair Display',serif;font-size:20rem;line-height:.6;color:rgba(255,255,255,.03);position:absolute;top:0;left:4vw;pointer-events:none}
.qtx{font-family:'Playfair Display',serif;font-size:clamp(1.4rem,3vw,2.2rem);font-style:italic;color:#fff;line-height:1.5;max-width:760px;margin:0 auto 18px}
.qau{font-size:.8rem;letter-spacing:.14em;text-transform:uppercase;color:var(--light);font-weight:500}
.ahero{background:linear-gradient(150deg,var(--navy),var(--deep));padding:72px 8vw 64px;padding-top:calc(72px + 68px);position:relative;overflow:hidden}
.awm{position:absolute;right:4vw;bottom:-20px;font-family:'Playfair Display',serif;font-size:clamp(5rem,14vw,12rem);font-weight:700;color:rgba(37,99,235,.06);line-height:1;pointer-events:none;user-select:none}
.aheye{font-size:.72rem;letter-spacing:.18em;text-transform:uppercase;color:var(--sky);font-weight:600;margin-bottom:12px;display:flex;align-items:center;gap:10px}
.aheye::before{content:'';width:20px;height:2px;background:var(--sky)}
.ahti{font-family:'Playfair Display',serif;font-size:clamp(2.2rem,5vw,3.8rem);font-weight:700;color:#fff;line-height:1.1;margin-bottom:12px}
.ahti em{font-style:italic;color:var(--light)}
.ahsu{font-size:.9rem;color:rgba(147,197,253,.5);max-width:560px;line-height:1.8}
.og{display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:start}
.ob p{font-size:.92rem;line-height:1.9;color:var(--muted);margin-bottom:16px}
.hl{color:var(--royal);font-weight:600}
.oa{display:flex;flex-direction:column;gap:14px}
.ic{background:var(--card);border:1px solid var(--border);border-radius:10px;padding:20px 22px 18px;position:relative;overflow:hidden}
.ic::before{content:'';position:absolute;left:0;top:0;bottom:0;width:4px;background:linear-gradient(180deg,var(--bright),var(--sky));border-radius:10px 0 0 10px}
.ic h4{font-family:'Playfair Display',serif;font-size:.95rem;font-weight:600;margin-bottom:6px}
.ic p,.ic li{font-size:.83rem;line-height:1.75;color:var(--muted)}.ic ul{padding-left:16px}.ic li{margin-bottom:3px}
/* ── Mission / Vision / Values ──────────────────────────────── */
.mvvsec{padding:0 0 0;max-width:1080px;margin:0 auto}
.mvvg{display:flex;flex-direction:column;gap:0;border-radius:20px;overflow:hidden;box-shadow:0 24px 80px rgba(13,33,72,.13);border:1px solid rgba(37,99,235,.12)}
.mvv{display:grid;grid-template-columns:260px 1fr;min-height:172px;position:relative;transition:background .35s}
.mvv+.mvv{border-top:1px solid rgba(255,255,255,.06)}
.mvv.mi{background:linear-gradient(100deg,#0d2148 0%,#1a4fad 100%)}
.mvv.vi{background:linear-gradient(100deg,#1a4fad 0%,#2563eb 100%)}
.mvv.va{background:linear-gradient(100deg,#163775 0%,#0d2148 100%)}
.mvv-left{display:flex;flex-direction:column;align-items:center;justify-content:center;gap:14px;padding:36px 28px;border-right:1px solid rgba(255,255,255,.10);position:relative;overflow:hidden}
.mvv-left::before{content:'';position:absolute;inset:0;background:rgba(0,0,0,.09)}
.mvv-icon-wrap{width:62px;height:62px;border-radius:50%;background:rgba(255,255,255,.12);border:1.5px solid rgba(255,255,255,.22);display:flex;align-items:center;justify-content:center;position:relative;z-index:1;backdrop-filter:blur(4px)}
.mvv-icon-wrap svg{width:28px;height:28px;stroke:#fff;fill:none;stroke-width:1.8}
.mvv-label{font-family:'Playfair Display',serif;font-size:1.05rem;font-weight:700;color:#fff;letter-spacing:.02em;text-align:center;position:relative;z-index:1;text-transform:uppercase;font-size:.72rem;letter-spacing:.16em;font-family:'Plus Jakarta Sans',sans-serif}
.mvv-right{padding:32px 40px;display:flex;flex-direction:column;justify-content:center;gap:8px}
.mvv-title{font-family:'Playfair Display',serif;font-size:1.25rem;font-weight:700;color:#fff;line-height:1.3}
.mvv-body{font-size:.885rem;line-height:1.85;color:rgba(255,255,255,.78);max-width:620px}
.mvv-accent{width:36px;height:3px;border-radius:2px;background:rgba(255,255,255,.35);margin-bottom:4px}
@media(max-width:680px){.mvv{grid-template-columns:1fr}.mvv-left{border-right:none;border-bottom:1px solid rgba(255,255,255,.08);padding:24px}.mvv-right{padding:20px 24px}}
.chsec{background:linear-gradient(135deg,#eef4ff,var(--pale));padding:88px 8vw}
.chcard{background:var(--card);border:1px solid var(--border);border-radius:20px;overflow:hidden;display:grid;grid-template-columns:310px 1fr;box-shadow:0 12px 56px rgba(37,99,235,.13);max-width:1040px;margin:0 auto}
.chleft{background:linear-gradient(160deg,var(--deep),var(--royal));display:flex;flex-direction:column;align-items:center;justify-content:center;padding:48px 28px;text-align:center;position:relative;overflow:hidden}
.chleft::after{content:'';position:absolute;inset:0;background-image:linear-gradient(rgba(147,197,253,.06) 1px,transparent 1px),linear-gradient(90deg,rgba(147,197,253,.06) 1px,transparent 1px);background-size:32px 32px}
.chav{position:relative;z-index:2;width:136px;height:136px;border-radius:50%;overflow:hidden;margin-bottom:18px;border:4px solid rgba(255,255,255,.2);box-shadow:0 8px 32px rgba(0,0,0,.3);background:linear-gradient(135deg,var(--sky),var(--light))}
.chav img{width:100%;height:100%;object-fit:cover;object-position:top}
.chna{position:relative;z-index:2;font-family:'Playfair Display',serif;font-size:1.35rem;font-weight:700;color:#fff;margin-bottom:4px}
.chde{position:relative;z-index:2;font-size:.69rem;letter-spacing:.12em;text-transform:uppercase;color:var(--light);margin-bottom:20px;font-weight:500}
.chbgs{position:relative;z-index:2;display:flex;flex-direction:column;gap:7px;width:100%}
.chbg{background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.14);border-radius:8px;padding:8px 10px;font-size:.73rem;color:rgba(255,255,255,.8);text-align:center}
.chbg strong{color:#fff;display:block;font-size:.77rem}
.chri{padding:42px 46px}
.chri .stag{margin-bottom:10px}
.chrn{font-family:'Playfair Display',serif;font-size:clamp(1.5rem,3vw,2.2rem);font-weight:700;line-height:1.2;color:var(--navy);margin-bottom:8px}
.chrn em{font-style:italic;color:var(--bright)}
.chrt{display:inline-block;background:var(--pale);color:var(--royal);font-size:.7rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;padding:5px 14px;border-radius:100px;margin-bottom:22px;border:1px solid var(--border)}
.bio p{font-size:.89rem;line-height:1.9;color:var(--muted);margin-bottom:14px}.bio p:last-child{margin-bottom:0}
.exsec{margin-top:22px}.exsec h4{font-size:.73rem;letter-spacing:.14em;text-transform:uppercase;color:var(--bright);font-weight:600;margin-bottom:10px}
.etags{display:flex;flex-wrap:wrap;gap:7px}
.etag{padding:5px 13px;border-radius:100px;border:1px solid var(--border);font-size:.73rem;color:var(--navy);font-weight:500;background:var(--white);transition:all .2s;cursor:default}
.etag:hover{background:var(--bright);color:#fff;border-color:var(--bright)}
.chlinks{margin-top:20px;display:flex;gap:9px;flex-wrap:wrap}
.chlk{display:inline-flex;align-items:center;gap:7px;padding:9px 16px;border-radius:6px;border:1px solid var(--border);font-size:.77rem;font-weight:500;color:var(--navy);text-decoration:none;background:var(--white);transition:all .2s}
.chlk:hover{background:var(--bright);color:#fff;border-color:var(--bright);box-shadow:0 4px 16px rgba(37,99,235,.3)}
.chlk svg{width:14px;height:14px;stroke:currentColor;fill:none;stroke-width:2}
.tgrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(185px,1fr));gap:18px}
.tcard{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:26px 18px;text-align:center;transition:transform .3s,box-shadow .3s}
.tcard:hover{transform:translateY(-5px);box-shadow:0 12px 40px rgba(37,99,235,.12)}
.tav{width:62px;height:62px;border-radius:50%;margin:0 auto 12px;display:flex;align-items:center;justify-content:center;font-family:'Playfair Display',serif;font-size:1.25rem;font-weight:700;color:#fff}
.tav.photo{background:none;overflow:hidden;padding:0}
.tav.photo img{width:100%;height:100%;object-fit:cover;object-position:top;border-radius:50%}
.tna{font-family:'Playfair Display',serif;font-size:.93rem;font-weight:600;margin-bottom:3px}
.tro{font-size:.7rem;color:var(--muted)}.tin{font-size:.69rem;color:var(--bright);margin-top:4px;font-weight:500}
.tline{position:relative;padding-left:28px}
.tline::before{content:'';position:absolute;left:6px;top:0;bottom:0;width:2px;background:linear-gradient(to bottom,var(--bright),var(--light))}
.tli{position:relative;margin-bottom:30px}.tli:last-child{margin-bottom:0}
.tld{position:absolute;left:-24px;top:4px;width:12px;height:12px;border-radius:50%;background:var(--bright);border:2px solid var(--pale);box-shadow:0 0 0 3px rgba(37,99,235,.15)}
.tly{font-size:.69rem;font-weight:700;letter-spacing:.1em;color:var(--bright);text-transform:uppercase;margin-bottom:3px}
.tlt{font-family:'Playfair Display',serif;font-size:.97rem;font-weight:600;margin-bottom:4px;color:var(--navy)}
.tlx{font-size:.82rem;line-height:1.75;color:var(--muted)}
.evhero{background:linear-gradient(150deg,var(--navy),var(--deep));padding:70px 8vw 60px;padding-top:calc(70px + 68px);position:relative;overflow:hidden}
.evwm{position:absolute;right:4vw;bottom:-30px;font-family:'Playfair Display',serif;font-size:clamp(6rem,16vw,13rem);font-weight:700;color:rgba(37,99,235,.06);line-height:1;pointer-events:none;user-select:none}
.eveye{font-size:.72rem;letter-spacing:.18em;text-transform:uppercase;color:var(--sky);font-weight:600;margin-bottom:12px;display:flex;align-items:center;gap:10px}
.eveye::before{content:'';width:20px;height:2px;background:var(--sky)}
.evti{font-family:'Playfair Display',serif;font-size:clamp(2.2rem,5vw,3.8rem);font-weight:700;color:#fff;line-height:1.1;margin-bottom:10px}
.evti em{font-style:italic;color:var(--light)}
.evsu{font-size:.87rem;color:rgba(147,197,253,.5)}
.evtop{padding:16px 8vw;background:var(--white);border-bottom:1px solid var(--border);position:sticky;top:68px;z-index:99;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px}
.evfi{display:flex;gap:8px;flex-wrap:wrap}
.fbtn{display:inline-flex;align-items:center;gap:7px;padding:8px 18px;border-radius:100px;border:1.5px solid transparent;font-family:'Plus Jakarta Sans',sans-serif;font-size:.72rem;letter-spacing:.06em;text-transform:uppercase;cursor:pointer;transition:all .2s;font-weight:600}
.fbtn svg{width:14px;height:14px;stroke:currentColor;flex-shrink:0}
.fbtn-all{background:rgba(37,99,235,.08);border-color:rgba(37,99,235,.25);color:#1d4ed8}
.fbtn-all.active,.fbtn-all:hover{background:#1d4ed8;color:#fff;border-color:#1d4ed8}
.fbtn-hack{background:rgba(109,40,217,.08);border-color:rgba(109,40,217,.25);color:#6d28d9}
.fbtn-hack.active,.fbtn-hack:hover{background:#7c3aed;color:#fff;border-color:#7c3aed}
.fbtn-contest{background:rgba(217,119,6,.08);border-color:rgba(217,119,6,.3);color:#b45309}
.fbtn-contest.active,.fbtn-contest:hover{background:#d97706;color:#fff;border-color:#d97706}
.fbtn-mentor{background:rgba(5,150,105,.08);border-color:rgba(5,150,105,.25);color:#047857}
.fbtn-mentor.active,.fbtn-mentor:hover{background:#059669;color:#fff;border-color:#059669}
.fbtn-sem{background:rgba(124,58,237,.08);border-color:rgba(124,58,237,.25);color:#6d28d9}
.fbtn-sem.active,.fbtn-sem:hover{background:#7c3aed;color:#fff;border-color:#7c3aed}
.fbtn-celeb{background:rgba(234,88,12,.08);border-color:rgba(234,88,12,.25);color:#c2410c}
.fbtn-celeb.active,.fbtn-celeb:hover{background:#ea580c;color:#fff;border-color:#ea580c}
.evgrid{padding:44px 8vw 72px;display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:28px}
.evc{background:var(--card);border:1px solid var(--border);border-radius:14px;overflow:hidden;cursor:pointer;display:flex;flex-direction:column;transition:transform .35s cubic-bezier(.4,0,.2,1),box-shadow .35s;box-shadow:0 2px 12px rgba(10,22,40,.06);animation:cardIn .4s ease both}
@keyframes cardIn{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}
.evc:hover{transform:translateY(-10px);box-shadow:0 24px 64px rgba(26,79,173,.18)}
.evc:hover .ci img{transform:scale(1.07)}
.evc:hover .ccta{gap:10px;color:var(--bright)}
.ci{position:relative;overflow:hidden;aspect-ratio:16/9}
.ci img{width:100%;height:100%;object-fit:cover;transition:transform .6s cubic-bezier(.4,0,.2,1)}
.ciov{position:absolute;inset:0;background:linear-gradient(to top,rgba(10,22,40,.55),transparent 50%)}
.cbdg{position:absolute;top:14px;left:14px;background:var(--bright);color:#fff;font-size:.64rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;padding:5px 11px;border-radius:4px}
.cdt{position:absolute;top:14px;right:14px;background:rgba(10,22,40,.75);backdrop-filter:blur(8px);color:#fff;font-size:.7rem;padding:5px 10px;border-radius:4px}
.cbdy{padding:24px 24px 20px;flex:1;display:flex;flex-direction:column}
.ccat{font-size:.67rem;letter-spacing:.14em;text-transform:uppercase;color:var(--bright);font-weight:600;margin-bottom:7px}
.ctit{font-family:'Playfair Display',serif;font-size:1.28rem;font-weight:600;line-height:1.3;margin-bottom:11px;color:var(--navy)}
.cdsc{font-size:.84rem;line-height:1.8;color:var(--muted);flex:1;margin-bottom:18px}
.cft{display:flex;align-items:center;justify-content:space-between;border-top:1px solid var(--border);padding-top:14px}
.cloc{display:flex;align-items:center;gap:6px;font-size:.75rem;color:var(--muted)}
.cloc svg{width:13px;height:13px;stroke:var(--bright);fill:none;stroke-width:2}
.ccta{display:flex;align-items:center;gap:6px;font-size:.72rem;letter-spacing:.09em;text-transform:uppercase;color:var(--sky);font-weight:600;transition:all .25s}
.ccta svg{width:14px;height:14px;stroke:currentColor;fill:none;stroke-width:2}
.pgarr{width:36px;height:36px;border-radius:50%;border:none;background:transparent;color:var(--muted);cursor:pointer;display:flex;align-items:center;justify-content:center;transition:background .18s,color .18s;padding:0}
.pgarr:hover:not(:disabled){background:rgba(37,99,235,.09);color:var(--royal)}
.pgarr:disabled{opacity:.3;cursor:not-allowed}
.pgarr svg{width:20px;height:20px;stroke:currentColor;fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round}
.pg-range{font-size:.82rem;color:var(--muted);min-width:90px;text-align:center;letter-spacing:.01em}
.pg-sep{width:1px;height:20px;background:var(--border);margin:0 2px}
.pgdot,.pgdot-active{display:none}
footer{background:var(--navy);color:#93c5fd;padding:52px 8vw;display:grid;grid-template-columns:1fr 1fr 1fr;gap:40px}
.ftbr h3{font-family:'Playfair Display',serif;font-size:1.3rem;color:#fff;margin-bottom:8px}.ftbr p{font-size:.82rem;line-height:1.8;color:#fff}
.ftco h4{font-size:.71rem;letter-spacing:.14em;text-transform:uppercase;color:var(--sky);margin-bottom:14px}
.ftco a{display:block;font-size:.82rem;color:#93c5fd;text-decoration:none;margin-bottom:7px;transition:color .2s}.ftco a:hover{color:#fff}
.ftbt{grid-column:1/-1;border-top:1px solid rgba(147,197,253,.2);padding-top:22px;font-size:.77rem;text-align:center;color:#93c5fd}
@media(max-width:900px){.chcard{grid-template-columns:1fr}.og{grid-template-columns:1fr}}
@media(max-width:768px){footer{grid-template-columns:1fr}.pillars{grid-template-columns:1fr}}
@media(max-width:640px){.hstats{display:none}.evgrid{grid-template-columns:1fr}}
