<script data-cfasync="false" src="/cdn-cgi/scripts/5c5dd728/cloudflare-static/email-decode.min.js"></script><script>
var IMGS = {
  nariyukti:  'data:image/jpeg;base64,',
  ladyada:    'data:image/jpeg;base64,',
  gradcohort: 'data:image/jpeg;base64,'
};

var EV = [
  {key:'nariyukti',  badge:'2025',     date:'National Level', cl:'Hackathon',         title:'NariYukti Hackathon 2025',     loc:'Pan-India',  url:'https://event.india.acm.org/hackathon/home/',  desc:'The ACM-W India Hackathon NariYukti 25 is a flagship national-level initiative aimed at empowering women in computing by providing a platform to innovate, collaborate, and solve real-world problems. Open to undergraduate and postgraduate students, it encourages all-female teams to present impactful, technology-driven solutions. Shortlisted teams receive mentorship to refine their ideas into meaningful prototypes.'},
  {key:'ladyada',    badge:'Flagship', date:'Annual Event',   cl:'Coding Contest',    title:'Lady Ada Programming Contest', loc:'Pan-India',  url:'https://event.india.acm.org/ladyada/home/',    desc:'Lady Ada is the flagship annual event of ACM-W India, named in honor of Ada Lovelace the world first computer programmer. A national-level coding event designed to empower women in computing by showcasing technical skills, problem-solving abilities, and innovative thinking. The event brings together participants from across the country to compete, collaborate, and celebrate diversity and inclusion in technology.'},
  {key:'gradcohort', badge:'2025',     date:'IIT Kanpur',     cl:'Mentorship Program',title:'Grad Cohort 2025',              loc:'IIT Kanpur', url:'https://event.india.acm.org/gradcohort/home/', desc:'The ACM-W India Grad Cohort 2025 is a premier mentoring initiative empowering women in computing research across India. Hosted at IIT Kanpur, it brings together students, researchers, and industry leaders for guidance and inspiration. The program offers mentorship, keynote talks, and interactive sessions to support academic and research growth for women in Masters and Ph.D. programs.'}
];

var currentFilter = 'all';
var currentPage = 1;
var PER_PAGE = 6;

var CAT_COLORS = {
  'Hackathon':         {bg:'rgba(220,38,38,.08)',  border:'rgba(220,38,38,.25)',  color:'#b91c1c'},
  'Coding Contest':    {bg:'rgba(217,119,6,.08)',  border:'rgba(217,119,6,.3)',   color:'#b45309'},
  'Mentorship Program':{bg:'rgba(5,150,105,.08)', border:'rgba(5,150,105,.25)',  color:'#047857'},
  'Celebration':       {bg:'rgba(234,88,12,.08)',  border:'rgba(234,88,12,.25)',  color:'#c2410c'},
};

function filterEv(cat, btn) {
  currentFilter = cat;
  currentPage = 1;
  var btns = document.querySelectorAll('.fbtn');
  for (var i = 0; i < btns.length; i++) btns[i].classList.remove('active');
  if (btn) btn.classList.add('active');
  render();
}

function render() {
  var list = currentFilter === 'all' ? EV : EV.filter(function(e){ return e.cl === currentFilter; });
  var total = list.length;
  var totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
  if (currentPage > totalPages) currentPage = 1;
  var start = (currentPage - 1) * PER_PAGE;
  var pageItems = list.slice(start, start + PER_PAGE);

  var h = '';
  if (total === 0) {
    h = '<div style="grid-column:1/-1;text-align:center;padding:80px 0;color:var(--muted);font-size:.95rem;">No events in this category yet.</div>';
  } else {
    for (var i = 0; i < pageItems.length; i++) {
      var e = pageItems[i];
      var c = CAT_COLORS[e.cl] || {bg:'rgba(37,99,235,.08)',border:'rgba(37,99,235,.25)',color:'#1d4ed8'};
      var catStyle = 'background:'+c.bg+';border:1px solid '+c.border+';color:'+c.color+';font-size:.67rem;letter-spacing:.14em;text-transform:uppercase;font-weight:600;padding:3px 10px;border-radius:100px;display:inline-block;margin-bottom:7px;';
      h += '<div class="evc" style="animation-delay:' + (i * 0.1) + 's" data-url="' + e.url + '">' +
        '<div class="ci"><img src="' + IMGS[e.key] + '" alt="' + e.title + '"><div class="ciov"></div>' +
        '<span class="cbdg">' + e.badge + '</span><span class="cdt">' + e.date + '</span></div>' +
        '<div class="cbdy"><p style="'+catStyle+'">' + e.cl + '</p><h3 class="ctit">' + e.title + '</h3>' +
        '<p class="cdsc">' + e.desc + '</p>' +
        '<div class="cft"><span class="cloc"><svg viewBox="0 0 24 24" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>' + e.loc + '</span>' +
        '<span class="ccta">View Details <svg viewBox="0 0 24 24" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></span>' +
        '</div></div></div>';
    }
  }

  var grid = document.getElementById('evgrid');
  grid.innerHTML = h;
  var cards = grid.querySelectorAll('.evc');
  for (var j = 0; j < cards.length; j++) {
    cards[j].addEventListener('click', function() {
      window.open(this.getAttribute('data-url'), '_blank');
    });
  }

  // Pagination
  var pgEl = document.getElementById('ev-pagination');
  if (!pgEl) return;
  if (totalPages <= 1) {
    pgEl.style.display = 'none';
    return;
  }
  pgEl.style.display = 'flex';
  var end = Math.min(start + PER_PAGE, total);
  document.getElementById('ev-pg-info').textContent = (start + 1) + '–' + end + ' of ' + total;
  document.getElementById('ev-prev').disabled = currentPage <= 1;
  document.getElementById('ev-next').disabled = currentPage >= totalPages;
}

function showPage(id, btn) {
  var ps = document.querySelectorAll('.page');
  var ts = document.querySelectorAll('.nav-tab');
  for (var i = 0; i < ps.length; i++) ps[i].classList.remove('active');
  for (var i = 0; i < ts.length; i++) ts[i].classList.remove('active');
  document.getElementById('page-' + id).classList.add('active');
  if (btn) btn.classList.add('active');
  window.scrollTo({ top: 0, behavior: 'smooth' });
  if (id === 'events') render();
}

window.addEventListener('scroll', function() {
  var nav = document.getElementById('navbar');
  if (window.scrollY > 10) nav.classList.add('scrolled');
  else nav.classList.remove('scrolled');

  // Scroll spy: highlight active nav tab
  var sections = ['page-home', 'page-about', 'page-events'];
  var offset = 80;
  var current = sections[0];
  for (var i = 0; i < sections.length; i++) {
    var el = document.getElementById(sections[i]);
    if (el && el.getBoundingClientRect().top <= offset) {
      current = sections[i];
    }
  }
  var tabs = document.querySelectorAll('.nav-tab');
  var map = {'page-home': 0, 'page-about': 1, 'page-events': 2};
  for (var j = 0; j < tabs.length; j++) tabs[j].classList.remove('active');
  if (map[current] !== undefined) tabs[map[current]].classList.add('active');
});

document.addEventListener('DOMContentLoaded', function() {
  render();
});
</script>
